import{c as n,Q as a,j as t,m as i}from"./chunks/framework.BXc4yaFE.js";const g=JSON.parse('{"title":"Harness Design for Long-Running Application Development","description":"","frontmatter":{"title":"Harness Design for Long-Running Application Development","author":"Prithvi Rajasekaran","date":"2026-03-24T00:00:00.000Z","source":"https://www.anthropic.com/engineering/harness-design-long-running-apps","tags":["agent-harness","anthropic","research","harness-design","multi-agent"]},"headers":[],"relativePath":"research/agent-harness/references/2026-03-24-harness-design-long-running-apps-anthropic.md","filePath":"research/agent-harness/references/2026-03-24-harness-design-long-running-apps-anthropic.md","lastUpdated":1779894392000}'),r={name:"research/agent-harness/references/2026-03-24-harness-design-long-running-apps-anthropic.md"};function o(s,e,l,d,p,h){return a(),t("div",null,[...e[0]||(e[0]=[i('<h1 id="harness-design-for-long-running-application-development" tabindex="-1">Harness Design for Long-Running Application Development <a class="header-anchor" href="#harness-design-for-long-running-application-development" aria-label="Permalink to &quot;Harness Design for Long-Running Application Development&quot;">​</a></h1><p><strong>Published:</strong> Mar 24, 2026<br><strong>Author:</strong> Prithvi Rajasekaran, Anthropic Labs</p><h2 id="overview" tabindex="-1">Overview <a class="header-anchor" href="#overview" aria-label="Permalink to &quot;Overview&quot;">​</a></h2><p>This article explores how Anthropic improved Claude&#39;s ability to build complete applications without human intervention through innovative harness design patterns. The work addresses two key challenges: generating high-quality frontend designs and maintaining coherence during extended coding tasks.</p><h2 id="core-innovation-generator-evaluator-architecture" tabindex="-1">Core Innovation: Generator-Evaluator Architecture <a class="header-anchor" href="#core-innovation-generator-evaluator-architecture" aria-label="Permalink to &quot;Core Innovation: Generator-Evaluator Architecture&quot;">​</a></h2><p>Inspired by Generative Adversarial Networks (GANs), the author developed a multi-agent system pairing a generator with an evaluator. This separation addresses a fundamental problem: &quot;agents tend to respond by confidently praising the work—even when, to a human observer, the quality is obviously mediocre.&quot;</p><h3 id="frontend-design-application" tabindex="-1">Frontend Design Application <a class="header-anchor" href="#frontend-design-application" aria-label="Permalink to &quot;Frontend Design Application&quot;">​</a></h3><p>Four grading criteria guide design quality:</p><ul><li><strong>Design quality:</strong> Coherent visual identity and mood</li><li><strong>Originality:</strong> Evidence of custom decisions versus templates</li><li><strong>Craft:</strong> Typography, spacing, and color fundamentals</li><li><strong>Functionality:</strong> Usability and task completion</li></ul><p>The evaluator used Playwright to interact with live pages before scoring, enabling iterative refinement across 5-15 cycles per generation.</p><h3 id="full-stack-development-harness" tabindex="-1">Full-Stack Development Harness <a class="header-anchor" href="#full-stack-development-harness" aria-label="Permalink to &quot;Full-Stack Development Harness&quot;">​</a></h3><p>The final three-agent architecture includes:</p><ol><li><strong>Planner:</strong> Expands brief prompts into detailed product specifications with ambitious scope</li><li><strong>Generator:</strong> Implements features using React, Vite, FastAPI, and SQLite/PostgreSQL</li><li><strong>Evaluator:</strong> Tests functionality through user interactions via Playwright</li></ol><p>Key improvements over single-agent approaches:</p><ul><li>Sprint contracts negotiated between generator and evaluator before implementation</li><li>Structured file-based communication maintaining context</li><li>Reduced &quot;context anxiety&quot; behavior in newer models</li></ul><h2 id="key-findings" tabindex="-1">Key Findings <a class="header-anchor" href="#key-findings" aria-label="Permalink to &quot;Key Findings&quot;">​</a></h2><p><strong>Performance Gap:</strong> A retro game maker built with the full harness (6 hours, $200) produced dramatically superior results compared to solo generation (20 minutes, $9). The single-agent output had broken gameplay mechanics, while the harness version delivered functional, polished applications.</p><p><strong>Model Evolution:</strong> Opus 4.6 eliminated the need for sprint-based decomposition, allowing longer uninterrupted generation sessions. The author demonstrates that &quot;as models improve, the scaffold surrounding the model matters less over time.&quot;</p><p><strong>QA Effectiveness:</strong> The evaluator caught subtle issues like route ordering bugs and incomplete feature implementations that solo generation missed, though comprehensive testing remained challenging.</p><h2 id="cost-performance-tradeoff" tabindex="-1">Cost-Performance Tradeoff <a class="header-anchor" href="#cost-performance-tradeoff" aria-label="Permalink to &quot;Cost-Performance Tradeoff&quot;">​</a></h2><p>The simplified V2 harness (3 hours 50 minutes, $124.70) generated a functional Digital Audio Workstation with working timeline, mixer, and AI-assisted composition features—demonstrating that improved model capabilities enable harness optimization without sacrificing quality.</p><h2 id="design-principles" tabindex="-1">Design Principles <a class="header-anchor" href="#design-principles" aria-label="Permalink to &quot;Design Principles&quot;">​</a></h2><p>The author emphasizes: &quot;find the simplest solution possible, and only increase complexity when needed.&quot; As capabilities improve, practitioners should periodically audit which harness components remain load-bearing, removing unnecessary overhead while adding new capabilities at the frontier of what models can achieve.</p>',23)])])}const u=n(r,[["render",o]]);export{g as __pageData,u as default};
